Rule.Source:
  import sailpoint.object.Application;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.tools.Util;
  import org.json.simple.JSONArray;
  import org.json.simple.parser.JSONParser;
  import org.json.simple.JSONObject;
  import sailpoint.tools.Util;
  import java.io.InputStreamReader;
  import java.io.OutputStream;
  import java.net.HttpURLConnection;
  import java.net.URL;
  import java.util.Base64;
  import org.apache.commons.lang.StringUtils;
  import org.json.JSONObject;
  import sailpoint.api.IdentityService;
  
   Log logger= LogFactory.getLog("asc.voalte.addremoveentitlement");

  IdentityService idService = new IdentityService(context);
  List applinks = new ArrayList();

  String sessionVal = createSession();
  String sessionToken = "VoalteSession "+sessionVal;
  if(null != requestEndPoint){
    Map headerMap = requestEndPoint.getHeader();
    if (headerMap!=null && !Util.isEmpty(headerMap)) { 
      headerMap.put("Authorization",sessionToken);
      requestEndPoint.setHeader(headerMap);
    }
  }

  String nativeID=null;
  Long userId=0;
  List selectedRole=new ArrayList();
  if (provisioningPlan != null) {

    Identity identity = context.getObjectByName(Identity.class,provisioningPlan.getNativeIdentity());

    for (AccountRequest accReq : Util.iterate(provisioningPlan.getAccountRequests())) {
      if(accReq!=null) {

        nativeID = identity.getAttribute("samAccountName");
       
        for (ProvisioningPlan.AttributeRequest attReq : Util.iterate(accReq.getAttributeRequests())) {
          
          if(attReq!=null) {
            String attrName = attReq.getName();
            if (attrName != null && "role".equalsIgnoreCase(attrName)) {
              
              selectedRole.add(attReq.getValue());
            
              
            }
          }
        }
      }
    }
  } 

  
  String getUserDetails(String nativeID) {
   
    String userDetails = "";
    
    if ( null == application ) {
      throw new RuntimeException("Voalte Application details does not exist in IIQ ");
    }

    String finalUrl = application.getAttributeValue("genericWebServiceBaseUrl") + "users?search_filter_value=username&search_value="+nativeID;
   
    URL url = new URL(finalUrl);
    if( url != null) {
      try {
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        if (null != conn) {
          conn.setRequestMethod("GET");
          conn.setRequestProperty("Content-Type", "application/json");
          conn.setRequestProperty("Accept", "application/json");
          
          Map property=requestEndPoint.getHeader();

          String authHeader =	property.get("Authorization");
        
          conn.setRequestProperty("Authorization", authHeader);

          int responseCode = conn.getResponseCode();
          if(responseCode != HttpURLConnection.HTTP_OK) {
            throw new RuntimeException("Minting Svc Failed: Received HTTP Code " + responseCode);
          }

          BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()));
          userDetails = br.readLine();
		  br.close();
        }
      } catch(IOException e) {
        logger.error("IO Exceptions while retrieving users existing details "+e.getMessage());
      } catch(Exception e) {
        logger.error("Exceptions while retrieving users existing details "+e.getMessage());
      }
    } else {
      logger.error("Unable to get retrieve URL details ");
    }
    return userDetails;
  }

  String raw_Response = getUserDetails(nativeID);
 
  Map returnMap=new HashMap();
  List valueList=new ArrayList();
  if(raw_Response !=null){
    JSONParser parse = new JSONParser();
    JSONArray mainObj = (JSONArray )parse.parse(raw_Response);
  
    if(null != mainObj) {
      for(org.json.simple.JSONObject currentIdentifier :mainObj ) {
        userId=currentIdentifier.get("id");
 
        JSONArray assignments= currentIdentifier.get("assignments");

        for(org.json.simple.JSONObject eachRole :assignments) {
     
          Map role= eachRole.get("role");
          boolean defaultval= eachRole.get("default");
        
          Long id=role.get("id");
        
          String mergedval=Util.otos(defaultval) +":"+Util.otos(id);
          returnMap.put(Util.otos(id),mergedval);
       
        }
      }
    }



    try{
      String newBody="";
    
   
      int count=0;
      String opType=requestEndPoint.getOperationType();
      
      if(returnMap!=null && !returnMap.isEmpty() && selectedRole!=null){
          for(String eachRoleFromPlan : selectedRole){
            if("Add Entitlement".equalsIgnoreCase(opType) && null == returnMap.get(eachRoleFromPlan)){
              returnMap.put(eachRoleFromPlan,"false:"+eachRoleFromPlan);
            }
            else if ("Remove Entitlement".equalsIgnoreCase(opType)){
              returnMap.remove(eachRoleFromPlan);
             
            }       
          }
      }
      else{  
        for(String eachRoleFromPlan :selectedRole){
          if(returnMap.isEmpty()){
            returnMap.put(eachRoleFromPlan,"true:"+eachRoleFromPlan);
          }
          else{
            returnMap.put(eachRoleFromPlan,"false:"+eachRoleFromPlan);
          }
        }
      }

      if(null != returnMap){
        for(Map.Entry eachAttrEntry : returnMap.entrySet()){
          String key= eachAttrEntry.getKey();
         
          String val=returnMap.get(key);
          String[] valarr=val.split(":");
          val=valarr[0];
         
          newBody=newBody+"{\"default\":"+val+",\"role\":"+key+"},";        
        }
      }

      if( null != newBody && newBody.endsWith(",")){
        newBody=StringUtils.stripEnd(newBody, ",");
      }


      Map map = requestEndPoint.getBody();

      String body=null;
      if (map!=null && map.get("jsonBody")!=null) {
        String contextURL="users/"+userId;
        String oldCtxURL=requestEndPoint.getContextUrl();
        requestEndPoint.setContextUrl(contextURL);
        String fullUrl=requestEndPoint.getFullUrl();  
        String fullUrlModi=fullUrl.replace(oldCtxURL,contextURL);

        requestEndPoint.setFullUrl(fullUrlModi);                             
        body = map.get("jsonBody").toString();
        body="{\"assignments\":["+newBody+"]}";
        map.put("jsonBody", body);
        requestEndPoint.setBody(map);

      }

    }catch(Exception e) {
      logger.error("Exception in Volate Add or Remove Entitlement before Operation rule "+e.getMessage());
    }

  }

  return requestEndPoint;
